def rotate_alphabet(start_letter, rotations):
    alphabet = 'abcdefghijklmnopqrstuvwxyz'
    start_index = alphabet.index(start_letter)
    for i in range(26):
        yield alphabet[(start_index + i) % 26]

if __name__ == "__main__":
    start = input().strip()
    rotations = int(input().strip())

    for letter in rotate_alphabet(start, rotations):
        print(letter, end='')
    print()  # Print a newline at the end
